INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('46f90863-e5de-4bfc-9b62-7c5ae14462c7', '78300cb2-7f07-4d18-b8d9-394ed4bcb202', 2, 16, 7, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","title":"Quán bánh cuốn ngon gần đây","restaurants":[{"name":"Bánh Cuốn Thanh Trì","address":"30 P. Thanh Đàm, Vĩnh Hưng","mapUrl":"https://maps.app.goo.gl/xn5bu3zBLnBYERqq7","image":{"url":"https://lh3.googleusercontent.com/gps-cs-s/APNQkAGaW4lcPfVdJ2VnFgUoYWfI4HxBMIHYfU02MkHCRSwxLcnRu532hmqROp6gfhlub7do2Lt5kqu9ILVnWzMBcesNd7v03MmVqirkmC8nwdi_4vagQ0nJKz9WKrIm8_2GzGFOoG8s=w408-h408-k-no","scale":"cover","focalPoint":"center"}},{"name":"Bánh cuốn Thanh Trì cô Tuyên","address":"3a, ngõ 924/115 Đ. Nguyễn Khoái, Vĩnh Hưng","mapUrl":"https://maps.app.goo.gl/KBLqKew2Sj6XM9Sk8","image":{"url":"https://lh3.googleusercontent.com/gps-cs-s/APNQkAGnJEJ6O1ZHhueBdxo5gCmMjH8aMdPqysPvmBnaWaUuE0HX9220FKxiHksmsfQrs4b6iU-dPdtcVOK2Yp5cTg7mEM-d_X3ulijb9WQhIm5oF9zRVgZqz9fBUNf2eaiDrIZwjSHi=w408-h408-k-no","scale":"cover","focalPoint":"center"}},{"name":"Bánh Cuốn Thanh Trì Việt Lý","address":"902 Đ. Nguyễn Khoái, Tổ DP số 30, Vĩnh ","mapUrl":"https://maps.app.goo.gl/nHQvzScoDSGPfpr56","image":{"url":"https://lh3.googleusercontent.com/gps-cs-s/APNQkAFF-LiNz17OVrK044c1VqV-BjF5T1MCHxIKnnb1oTrVjs8KGk8fRACRYqNy-TQD7fFvJ6j_4akjPefbWDznrY46NEUen4oO3HYe9ZoWvzMRx7PC5yupLGTcU9kXjZivd6vkS9H8Ug=w408-h544-k-no","scale":"cover","focalPoint":"53% 1%"}}]}', '2026-07-02 19:37:21.723333+07', '2026-07-02 19:37:21.723333+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('96027619-11c8-43b8-bc30-f2ae2891163a', '78300cb2-7f07-4d18-b8d9-394ed4bcb202', 2, 2, 1, true, '{"title":"Giới thiệu","content":"<p style=\"text-align:justify;\">Bánh cuốn Thanh Trì là một trong những món ăn lâu đời và thanh nhã của Hà Nội, nổi tiếng với lớp bánh trắng mỏng, mềm mịn như lụa. Không nhân cầu kỳ như nhiều loại bánh cuốn khác, bánh cuốn Thanh Trì chinh phục thực khách bằng hương thơm của gạo mới, vị ngọt thanh của nước chấm và nét tinh tế trong từng công đoạn chế biến.</p>","image":{"url":"https://static.vinwonders.com/production/banh-cuon-thanh-tri-4.jpeg","scale":"cover","focalPoint":"center"}}', '2026-07-02 19:37:21.723004+07', '2026-07-02 19:37:21.723004+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('bbb42e8d-576b-4e49-99f8-4c00c649a053', '78300cb2-7f07-4d18-b8d9-394ed4bcb202', 8, 14, 4, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","title":"THÀNH PHẦN CHÍNH","subtitle":"","items":[{"image":{"url":"https://cdn.baophapluat.vn/w3840/uploaded/images/2026/03/20/5724b514-75cf-4b48-9531-2b10114da736.jpg","scale":"cover","focalPoint":"center"},"title":"BÁNH CUỐN","description":"<p>• Gạo tẻ ngon (ủ vừa độ).<br>• Nước sạch tinh khiết.<br>• Một chút muối hạt tạo độ đậm cho cốt bột.</p>","tag":""},{"image":{"url":"https://mayviendong.vn/wp-content/uploads/2020/06/maxresdefault.jpg","scale":"cover","focalPoint":"center"},"title":"HÀNH PHI","description":"<p>• Hành củ tươi thái mỏng.<br>• Chao dầu đều tay.<br>• Đạt độ vàng ruộm và giòn rụm tự nhiên.</p>","tag":""},{"image":{"url":"https://cdn.tgdd.vn/2022/01/CookRecipe/GalleryStep/thanh-pham-93.jpg","scale":"cover","focalPoint":"68% 100%"},"title":"CHẢ QUẾ","description":"<p>• Chả quế nướng thơm lừng.<br>• Hoặc chả lụa Ước Lễ đượm vị.<br>• Cắt vát mỏng bày cạnh bánh.</p>","tag":""},{"image":{"url":"https://cdn3.ivivu.com/2022/09/n%C6%B0%E1%BB%9Bc-ch%E1%BA%A5m.jpg","scale":"cover","focalPoint":"center"},"title":"NƯỚC CHẤM","description":"<p>• Nước mắm cốt nguyên chất.<br>• Tỷ lệ vàng cùng đường, giấm hoặc chanh.<br>• Điểm xuyết tỏi và ớt băm.</p>","tag":""}],"backgroundColor":"#fafafa"}', '2026-07-02 19:37:21.723257+07', '2026-07-02 19:37:21.723258+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('5401aa82-b948-489b-a7d8-536ff36f9202', 'b33efe2f-cf38-4dcb-852f-3944dc5db52c', 2, 16, 6, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","title":"Gợi ý quán ngon","restaurants":[{"name":"Bún bò Mệ Kéo","address":"20 Bạch Đằng, tổ 19, Phú Xuân","mapUrl":"https://maps.app.goo.gl/AK7Sd3zDU6AGFo7S8","image":{"url":"https://lh3.googleusercontent.com/gps-cs-s/APNQkAHzOEOTBvedctMsREuhymYZxn5Lo1GkQ8kliYUmfHZf0GpLgq8f4qw-oJKjW90VSyYWatOhVnC6yB_UnlbykDQEOgPFkAUcnMceixNmK3qYcVZxgCrwAbn3qzdNqc0i6wQT43-yD0InIxuP=w408-h408-k-no","scale":"cover","focalPoint":"48% 1%"}},{"name":"Bún bò Mụ Rơi","address":"40 Nguyễn Chí Diểu, Phú Xuân","mapUrl":"https://maps.app.goo.gl/nyU7yDayMZa23zF28","image":{"url":"https://lh3.googleusercontent.com/gps-cs-s/APNQkAFhQB_hHnTT5yLo1mYMGYoUox_WIpzvyuJ2MobELL-gkoNDy_fXm0wq-IUI29-g7zPYb9K2jL36_zu8LYRHqBAzD37F4E9GiLsOxHWwSrCVGlg-67gGNmS2OMfTTLfDveX_olrbRIgd6YRg=w426-h240-k-no","scale":"cover","focalPoint":"49% 42%"}},{"name":"Bún cơm nguội Cảnh Vân","address":"198B kiet 4 Chi Lăng tổ 3, Phú Xuân","mapUrl":"https://maps.app.goo.gl/HQZfuQPVbCCdKgqR9","image":{"url":"https://lh3.googleusercontent.com/gps-cs-s/APNQkAHDrfk5CvkN0eJ6YbutV9sgbQsJ2zFKGq8co4suCeSYc6WO0xOL4bMALHBLllZSiwXJJeh_DSUqXVoW5RaPzDCppjnWKeBwUEbGjHi0cWeEaZrIUQkIwAELw96v3vkWFw2TVXJY=w426-h240-k-no","scale":"cover","focalPoint":"center"}}]}', '2026-07-03 11:29:08.755846+07', '2026-07-03 11:29:08.755846+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('6e29b5a2-b5fb-4f1e-8b89-9d48d01154c9', 'b33efe2f-cf38-4dcb-852f-3944dc5db52c', 8, 14, 3, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","title":"NGUYÊN LIỆU CHÍNH","subtitle":"","items":[{"image":{"url":"https://cdn.yeutre.vn/medias/webnauan.vn/33/33906/cach-nau-nuoc-dung-bun-bo-hue-600x400.jpg","scale":"cover","focalPoint":"center"},"title":"NƯỚC DÙNG ĐẬM ĐÀ","description":"<p>• Xương bò/heo hầm từ 8–12 giờ.<br>• Sả cây đập dập, hành gừng nướng.<br>• Mắm ruốc Huế cốt truyền thống.<br>• Dầu điều và dầu ớt đỏ rực.</p>","tag":""},{"image":{"url":"https://bunminhngoc.com/uploads/source/san-pham/soi-bun-bo.jpg","scale":"cover","focalPoint":"center"},"title":"SỢI BÚN HUẾ","description":"<p>• Sợi bún tròn, to đặc trưng.<br>• Làm từ gạo tinh tuyển.<br>• Đạt độ dai mềm chuẩn mực, thấm đều nước dùng.</p>","tag":""},{"image":{"url":"https://laque.vn/wp-content/uploads/2022/06/bb3.jpg","scale":"cover","focalPoint":"center"},"title":"THỊT BÒ PHONG PHÚ","description":"<p>• Bắp bò, nạm bò tươi ngon.<br>• Gân bò giòn, giò heo béo ngậy.<br>• Chả cua Huế vàng óng, tiết heo mềm bùi.</p>","tag":""},{"image":{"url":"https://giadinh.mediacdn.vn/2020/4/14/photo-1-15868738032831376310491.jpg","scale":"cover","focalPoint":"center"},"title":"RAU VÀ GIA VỊ KÈM","description":"<p>• Hoa chuối bào, rau muống chẻ.<br>• Giá đỗ, xà lách, húng quế.<br>• Chanh tươi, ớt chưng và giấm tỏi.</p>","tag":""}],"backgroundColor":"#fafafa"}', '2026-07-03 11:29:08.755809+07', '2026-07-03 11:29:08.755809+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('ea5ab1b2-47be-4fa7-ae33-34954872d4bb', '42d725c6-dd5a-42ca-acc7-d39bc6db7f49', 2, 17, 4, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","topText":"<h2>Cảm nhận hương vị</h2>\n<p style=\"text-align:justify;\">Hạt xôi tơi rời, dẻo bùi thơm mùi nếp mới hòa quyện nhịp nhàng với bát chè hoa cau sánh nhẹ, ngọt thanh không gắt. Tổng thể mang đến sự cân bằng, thanh nhã đặc trưng của ẩm thực Hà Nội.</p>","image":{"url":"https://media.suckhoecong.vn/Images/2025/03/28/z6450887833669_09a5d2f25d7af23ae3ce8e5da13b8a4e-15382192-250328153821.jpg","scale":"cover","focalPoint":"center"},"bottomText":"<h2 style=\"text-align:justify;\">Thưởng thức tại quán:</h2><p style=\"text-align:justify;\">Thưởng thức bát chè hoa cau lúc còn ấm nóng, cảm nhận rõ hương hoa bưởi phảng phất.</p><h2 style=\"text-align:justify;\"><br>Đặt hàng Online:</h2><p style=\"text-align:justify;\">Cặp món này cực kỳ dễ đóng gói mang đi; xôi tơi ráo không bị dính khối, chè được đóng hộp kín giữ nhiệt tốt.</p>","backgroundColor":"#ffffff"}', '2026-07-01 10:46:20.837543+07', '2026-07-01 10:46:20.837543+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('18b1eef1-752d-4c37-a1f0-17d222919449', 'fa85608a-62d6-4524-a0e7-3a380897f7d0', 2, 3, 1, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","title":"Giới thiệu","content":"<p style=\"text-align:justify;\">Bánh đa cua là món ăn tiêu biểu của Hải Phòng, gắn liền với đời sống người dân thành phố cảng suốt nhiều thế hệ. Nổi bật với sợi bánh đa đỏ đặc trưng, nước dùng ngọt thanh từ cua đồng và nhiều loại topping hấp dẫn, món ăn mang hương vị mộc mạc nhưng đậm đà, trở thành niềm tự hào trong bản sắc ẩm thực Hải Phòng.</p>","image":{"url":"https://statics.vinpearl.com/banh-da-cua-hai-phong-o-ha-noi-1_1687012182.jpg","scale":"cover","focalPoint":"center"},"backgroundColor":"#ffffff"}', '2026-07-02 20:03:40.584695+07', '2026-07-02 20:03:40.584695+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('945031b5-741f-4cb9-a459-56353223aa1c', 'b2a66e42-ba94-4545-8214-120d5d087414', 2, 3, 2, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","title":"Ra đời","content":"<p style=\"text-align:justify;\">Xuất hiện vào cuối thế kỷ XIX, đầu thế kỷ XX tại vùng đồng bằng Bắc Bộ và nhanh chóng phát triển mạnh ở Hà Nội. Gắn liền từ những gánh phở rong trên phố cổ đến các quán gia truyền nổi tiếng, trở thành một phần không thể thiếu trong đời sống thường nhật của người dân thủ đô.</p>","image":{"url":"https://static.vinwonders.com/production/Pho-ga-Ha-Noi-9.jpg","scale":"cover","focalPoint":"center"},"backgroundColor":"#ffffff"}', '2026-06-30 11:03:43.583315+07', '2026-06-30 11:03:43.583316+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('11e2d4b0-671e-4853-98ea-3b247d34b87f', '5a10eb2c-dc8f-4da8-b2f9-fe4a03c0edfa', 8, 14, 3, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","title":"NGUYÊN LIỆU CHÍNH","subtitle":"","items":[{"image":{"url":"https://i.ytimg.com/vi/VWeG7sYElpc/hq720.jpg?sqp=-oaymwEhCK4FEIIDSFryq4qpAxMIARUAAAAAGAElAADIQj0AgKJD&rs=AOn4CLAnNdJ3CDLnLaMx7t9tb-FP7HXcGg","scale":"cover","focalPoint":"center"},"title":"NHÂN CUA ĐỒNG QUÊ","description":"Sợi bún trắng mềm, thanh vị, được làm từ gạo tinh tuyển.","tag":""},{"image":{"url":"https://vcdn1-giadinh.vnecdn.net/2022/11/19/Buoc-2-2-6089-1668826337.jpg?w=1020&h=0&q=100&dpr=1&fit=crop&s=HYFtGt_AQroLvURXq79JBQ","scale":"cover","focalPoint":"center"},"title":"HẢI SẢN & RAU CỦ","description":"<p>• Thịt vai xay, mộc nhĩ, nấm hương, miến<br>•&nbsp;Rau củ quả thái nhỏ<br>• 2 - 3 lòng đỏ trứng gà</p>","tag":""},{"image":{"url":"https://photo.znews.vn/w660/Uploaded/ngotno/2020_03_15/halo.jpg","scale":"cover","focalPoint":"center"},"title":"VỎ BÁNH ĐA NEM","description":"<p>• Bánh đa nem bản lớn đặc trưng.<br>• Độ dẻo dai cao để gói nhân vuông.<br>• Khi chiên tạo độ giòn xốp dứt khoát.</p>","tag":""},{"image":{"url":"https://static.hawonkoo.vn/hwk02/images/2024/04/lam-nuoc-mam-cham-nem-cua-be.jpg","scale":"cover","focalPoint":"center"},"title":"ĐỒ ĂN KÈM VÀ NƯỚC CHẤM","description":"<p>• Nước mắm pha chua ngọt.<br>• Đu đủ xanh hoặc dưa góp ngâm.<br>• Rau xà lách và rau thơm vùng biển.</p>","tag":""}],"backgroundColor":"#fafafa"}', '2026-07-03 11:28:56.736795+07', '2026-07-03 11:28:56.736795+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('229e6abc-1d61-4b1e-aa7b-022eef7ed934', '5a10eb2c-dc8f-4da8-b2f9-fe4a03c0edfa', 2, 3, 2, true, '{"title":"Nguồn gốc","content":"<p style=\"text-align: justify; text-align-last: right;\">Ra đời tại Hải Phòng – thành phố cảng nổi tiếng với nguồn hải sản phong phú. Khác với nem rán truyền thống có dạng cuốn dài, người dân Hải Phòng đã sáng tạo nên chiếc nem hình vuông để chứa được nhiều nhân cua và hải sản hơn, giúp món ăn có hình thức đẹp mắt. Món ăn nhanh chóng trở thành một phần đặc trưng trong đời sống thường nhật và các dịp lễ, tiệc cưới địa phương</p>","image":{"url":"https://i-giadinh.vnecdn.net/2024/12/26/Thanhpham11-1735198211-1599-1735198217.jpg","scale":"cover","focalPoint":"bottom"},"textAlign":"right","marginTop":-30,"marginBottom":20}', '2026-07-03 11:28:56.736765+07', '2026-07-03 11:28:56.736766+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('2dae62c7-4afb-4532-9d82-1b4d16bf8492', '5a10eb2c-dc8f-4da8-b2f9-fe4a03c0edfa', 8, 14, 5, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","title":"ĐẶC TRƯNG HƯƠNG VỊ & ĐIỂM CHẠM THỰC TẾ","subtitle":"\"Muốn cảm nhận hương vị đất Cảng, hãy bắt đầu bằng một bát bánh đa cua nóng hổi.\"","items":[{"image":{"url":"https://chaca.com.vn/wp-content/uploads/2023/12/nem-cua-be.jpg","scale":"cover","focalPoint":"center"},"title":"Cảm nhận hương vị","description":"<p style=\"text-align:justify;\">Lớp vỏ giòn rụm, vàng óng bùng nổ vị giác ngay miếng cắn đầu tiên. Phần nhân cua biển ngọt tự nhiên hòa quyện với tôm, thịt băm và rau củ mềm ẩm bên trong, béo bùi vừa vặn mà không ngấy. Bát nước chấm chua ngọt thanh dịu cùng đu đủ xanh ngâm tạo nên sự cân bằng hương vị tròn đầy, tinh tế.</p>","tag":""},{"image":{"url":"https://vcdn1-dulich.vnecdn.net/2023/07/04/IMG-9865-1-1-6372-1688460337.jpg?w=1020&h=0&q=100&dpr=2&fit=crop&s=cpk-ku2FZN5iu5G-ix4bHg","scale":"cover","focalPoint":"center"},"title":"Thưởng thức","description":"<ul><li><strong>Thưởng thức tại quán</strong><br>Thưởng thức nem ngay khi vừa nhấc ra khỏi chảo dầu sôi, nem giữ được độ giòn tan, nhân nóng hổi đánh thức mọi giác quan.</li><li><strong>Đặt hàng Online</strong><br>Hoàn toàn có thể đặt hàng trực tuyến mang đi. Nhiều nhà hàng có phiên bản nem hút chân không hoặc nem chiên sơ kèm túi đá/hướng dẫn chiên lại bằng nồi chiên không dầu rất tiện lợi.</li></ul>","tag":""}],"backgroundColor":"#fafafa"}', '2026-07-03 11:28:56.736821+07', '2026-07-03 11:28:56.736821+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('def21c32-98ae-49d8-b3e5-87f56f1ca89b', '78300cb2-7f07-4d18-b8d9-394ed4bcb202', 2, 3, 3, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#931515","visibility":"all","title":"Nguồn gốc","content":"<p style=\"text-align:justify; color:#000000\">Có nguồn gốc từ làng cổ Thanh Trì, nằm ở phía Nam kinh thành Thăng Long xưa (nay thuộc quận Hoàng Mai, Hà Nội). Nghề bánh đã tồn tại hàng trăm năm, gắn liền với hình ảnh những gánh bánh cuốn và tiếng rao quen thuộc của các bà, các mẹ trong ngõ phố cổ từ tờ mờ sáng. Phiên bản truyền thống hoàn toàn không có nhân, chỉ tập trung tôn vinh hương vị nguyên bản của gạo và nước chấm</p>","image":{"url":"https://imagevietnam.vnanet.vn//MediaUpload/Org/2026/05/11/111-10-49-40.jpg","scale":"cover","focalPoint":"center"},"backgroundColor":"#ffffff"}', '2026-07-02 19:37:21.723093+07', '2026-07-02 19:37:21.723093+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('ac90a99e-e4f2-4ee5-ab1d-e44ee77e167e', 'b2a66e42-ba94-4545-8214-120d5d087414', 2, 17, 4, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","topText":"<h2 style=\"text-align:justify;\">Cảm nhận hương vị</h2><p style=\"text-align:justify;\">Nước dùng trong, ngọt thanh sâu từ xương hầm hòa quyện. Bánh phở mềm, thịt ngọt tự nhiên, tạo nên tổng thể thanh nhẹ.</p>","image":{"url":"https://static.vinwonders.com/production/pho-ha-noi-banner.jpg","scale":"cover","focalPoint":"center"},"bottomText":"<h2 style=\"text-align:right;\">Thưởng thức tại quán</h2><p style=\"text-align:justify;text-align-last:right;\">Thưởng thức phở ngay khi vừa chan nước dùng sôi sùng sục để cảm nhận hơi nóng đánh thức các giác quan trong tiết trời se lạnh.</p>","backgroundColor":"#ffffff"}', '2026-06-30 11:03:43.583554+07', '2026-06-30 11:03:43.583554+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('dd886a79-187c-43dd-b088-c7625d4bbf62', 'b2a66e42-ba94-4545-8214-120d5d087414', 2, 3, 1, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#794216","visibility":"all","title":"GIỚI THIỆU","content":"<p style=\"text-align:justify;\">Phở Hà Nội là món ăn biểu tượng của ẩm thực Việt Nam, gắn liền với hình ảnh thủ đô ngàn năm văn hiến. Với nước dùng trong, ngọt thanh từ xương hầm, bánh phở mềm mịn và thịt bò hoặc gà tươi ngon, phở không chỉ là một món ăn mà còn là niềm tự hào văn hóa, được bạn bè quốc tế biết đến và yêu thích.</p>","image":{"url":"https://media-cdn-v2.laodong.vn/storage/newsportal/2024/10/4/1403601/Pho-1-6.jpg","scale":"cover","focalPoint":"7% 89%"},"backgroundColor":"#ffffff"}', '2026-06-30 11:03:43.583276+07', '2026-06-30 11:03:43.583277+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('e7093c1f-9bc5-4ed5-9a68-72ac18dc7735', '78300cb2-7f07-4d18-b8d9-394ed4bcb202', 2, 4, 2, true, '{"title":"Nghệ thuật tráng bánh","content":"<p style=\"text-align:justify;\">Tráng bánh cuốn là một nghệ thuật đòi hỏi sự khéo léo và kiên nhẫn. Bột gạo được pha loãng, đổ một lớp mỏng lên mặt vải căng trên nồi nước sôi. Chỉ vài chục giây, lớp bánh trong suốt đã chín và được nhẹ nhàng cuộn lại với nhân thịt thơm ngon.</p>"}', '2026-07-02 19:37:21.723069+07', '2026-07-02 19:37:21.723069+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('eadd3796-8a3e-4af5-82f6-2be132c1838d', '78300cb2-7f07-4d18-b8d9-394ed4bcb202', 2, 17, 5, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","topText":"<h2>Cảm nhận hương vị</h2><p style=\"text-align:justify;\">Lớp bánh mỏng mềm như lụa, phảng phất hương thơm dịu của gạo mới, thanh nhẹ và không hề gây ngấy. Vị hành phi vàng giòn béo ngậy phối hợp nhịp nhàng với bát nước mắm pha chua ngọt tinh tế làm dậy lên hương vị nguyên bản mộc mạc.</p>","image":{"url":"https://hnm.1cdn.vn/2020/08/27/nhipsonghanoi.hanoimoi.com.vn-uploads-images-phananh-2020-08-27-_banh-cuon.jpg","scale":"cover","focalPoint":"center"},"bottomText":"<h2>Thưởng thức tại quán</h2><p>Khuyên dùng vào buổi sáng tại các ngõ phố nhỏ ven đường để cảm nhận sự bình yên và tinh tế của Hà Nội xưa.</p><h2>Đặt hàng Online</h2><p>Đặc sản này hoàn toàn có thể đặt mang đi. Lớp bánh dai mát tự nhiên kết hợp với hành phi để riêng giữ độ giòn, nước chấm đóng chai kín đáo rất tiện lợi.</p>","backgroundColor":"#ffffff"}', '2026-07-02 19:37:21.723288+07', '2026-07-02 19:37:21.723288+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('f941a8ad-9c3d-40db-af4a-4be1b752dd90', '78300cb2-7f07-4d18-b8d9-394ed4bcb202', 4, 6, 6, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","title":"Lịch sử","steps":[{"year":"Hàng trăm năm trước","title":"Ra đời","description":"Tại làng cổ Thanh Trì vùng ven Thăng Long."},{"year":"Đầu thế kỷ XX","title":"","description":"<p>Những gánh hàng rong tỏa đi khắp nẻo phố nội thành Hà Nội.</p>"},{"year":"Cuối thế kỷ XX","title":"","description":"Phục vụ rộng rãi tại quán ăn, trở thành món điểm tâm tiêu biểu."},{"year":"Hiện nay","title":"Di sản","description":"Món ăn đặc sản nhất định phải thử của du khách quốc tế."}],"backgroundColor":"#ffffff"}', '2026-07-02 19:37:21.723306+07', '2026-07-02 19:37:21.723306+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('2726b525-691e-4044-a49c-3f738876021f', 'b2a66e42-ba94-4545-8214-120d5d087414', 1, 1, 0, true, '{"title":"Phở Hà Nội","subtitle":"Hương vị truyền thống ngàn năm thơm ngon","imageUrl":"/Images/pho-bo-ha-noi.jpeg","image":{"url":"/uploads/infographics/pho1.jpg","scale":"cover","focalPoint":"100% 49%"},"textAlign":"center","description":"<p><i>\"Tinh hoa trong từng bát nước dùng – linh hồn của ẩm thực Hà Thành\"</i></p>"}', '2026-06-30 11:03:43.583193+07', '2026-06-30 11:03:43.583193+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('447465aa-9ef1-49c6-8426-88da81242cb9', 'b2a66e42-ba94-4545-8214-120d5d087414', 2, 16, 6, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","restaurants":[{"name":"Phở Bát Đàn","address":"49 Bát Đàn, Quận Hoàn Kiếm, Hà Nội","mapUrl":"https://maps.app.goo.gl/kmaTkwpvHSd91KFCA","image":{"url":"https://mia.vn/media/uploads/blog-du-lich/Pho-bat-dan-pho-gia-truyen-100-nam-tuoi-tai-ha-noi-01-1639325605.jpg","scale":"cover","focalPoint":"48% 2%"}},{"name":"Phở Thìn bờ hồ","address":"Số 61 Đinh Tiên Hoàng, Quận Hoàn Kiếm, Hà Nội","mapUrl":"https://maps.app.goo.gl/GYuKQnzKbEBbuoor5","image":{"url":"https://phothin1955.vn/sites/default/files/inline-images/pho-thi-bo-ho2.jpg","scale":"cover","focalPoint":"46% 2%"}},{"name":"Phở Lý Quốc Sư","address":"10 Lý Quốc Sư, Quận Hoàn Kiếm, Hà Nội","mapUrl":"https://maps.app.goo.gl/d72TSABuEuU4JCR29","image":{"url":"https://streetviewpixels-pa.googleapis.com/v1/thumbnail?panoid=uU-vH1vn3m_qgi38179d0w&cb_client=search.gws-prod.gps&w=408&h=240&yaw=246.01093&pitch=0&thumbfov=100","scale":"cover","focalPoint":"10% 47%"}}]}', '2026-06-30 11:03:43.583604+07', '2026-06-30 11:03:43.583604+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('4a11e7e9-87c9-478a-9fb5-2ddf20cc4c0a', '5a10eb2c-dc8f-4da8-b2f9-fe4a03c0edfa', 4, 6, 4, true, '{"paddingTop":40,"paddingBottom":40,"textAlign":"left","textColor":"#743e3e","visibility":"all","title":"LỊCH SỬ & DẤU MỐC NỔI BẬT","steps":[{"year":"Truyền thống","title":"Xuất hiện","description":"Hình thành từ mâm cơm các gia đình Hải Phòng, tận dụng nguồn cua biển dồi dào."},{"year":"Cuối thế kỷ XX","title":"Phổ biến","description":"Các tiệm ăn và nhà hàng chuyên nem cua bể ra đời, quảng bá món ăn ra ngoài thành phố."},{"year":"Thế kỷ XXI","title":"Nổi tiếng","description":"Vươn tầm quốc tế và được du khách nước ngoài đón nhận."},{"year":"Hiện nay","title":"Vị thế","description":"Là món ăn đại diện tiêu biểu của ẩm thực Hải Phòng, xuất hiện trong các cẩm nang du lịch."}],"backgroundColor":"#ffffff","marginTop":0,"marginBottom":0}', '2026-07-03 11:28:56.736812+07', '2026-07-03 11:28:56.736813+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('509f7d87-bf82-4ccd-b85c-60683f2c80b7', '5a10eb2c-dc8f-4da8-b2f9-fe4a03c0edfa', 2, 2, 1, true, '{"title":"Giới thiệu","content":"<p style=\"text-align:justify;\">Nem cua bể là một trong những đặc sản nổi tiếng nhất của Hải Phòng, gây ấn tượng bởi hình dáng vuông độc đáo và phần nhân đầy đặn từ thịt cua biển tươi ngon. Lớp vỏ vàng giòn bao bọc phần nhân ngọt thơm, kết hợp cùng nước chấm chua ngọt và rau sống tạo nên hương vị hài hòa, khiến món ăn trở thành niềm tự hào của ẩm thực đất Cảng.</p>","image":{"url":"https://cdn.netspace.edu.vn/images/2020/03/26/cach-lam-nem-cua-be-thom-ngon-gion-rum-244958-800.jpg","scale":"contain","focalPoint":"center"},"marginTop":0,"marginBottom":20}', '2026-07-03 11:28:56.736745+07', '2026-07-03 11:28:56.736745+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('7564f6c2-f333-46b1-981d-9e76606e60de', '5a10eb2c-dc8f-4da8-b2f9-fe4a03c0edfa', 2, 16, 6, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","title":"Gợi ý quán ngon","restaurants":[{"name":"Cửa Hàng bún chả Phương Mai","address":"87 P. Cát Cụt, Lê Chân","mapUrl":"https://maps.app.goo.gl/HEVrPnfTTLTGEunL9","image":{"url":"https://lh3.googleusercontent.com/gps-cs-s/APNQkAGt5s6dD_j3C7itHNL9ZXOPgjgjpDADwINA_ASfNVMSFR-nxtwqqHdhaFs7Lku-DN-F2W4S9Hn9hiZ50Y_Zm-1yavg4fW3d91AZlY0ffE7xPWfyhABJSrKmMp1CT6FuOcpKsyGyZ8nPbTXS=w408-h306-k-no","scale":"cover","focalPoint":"48% 1%"}},{"name":"Bún Chả Nem cua Hoàng Nhi","address":"334 P. Tô Hiệu, Lê Chân","mapUrl":"https://maps.app.goo.gl/22ip35j8M6Fx9Pm97","image":{"url":"https://lh3.googleusercontent.com/gps-cs-s/APNQkAHiwmNsdBk_yRGqm86eOPX7-JcFYSqUE-DO0ctydcYi5QVS4OFLNTkpVS8HTWunw9cA1EKDTl9_oTwemp2hrlhMCQ5dUANQPafEgueIKspBQ-2kTuemv5Rr8nr4-FmIeNdqYZh7hg=w408-h764-k-no","scale":"cover","focalPoint":"49% 42%"}},{"name":"Quán Nga Nem Cua Bể","address":"92 P. Trần Nhật Duật, Gia Viên","mapUrl":"https://maps.app.goo.gl/T4Mmr45g6C3AMg2w5","image":{"url":"https://lh3.googleusercontent.com/gps-cs-s/APNQkAEIR55KSyWBdoi0cyTBYKUA72hfNO6mon0ig_QivvJPaTWAQtGuh0F2it4mp96ShrQRQR4aeJTU_u9Y91D6axPNo36iw4ZOL25mWGy7bDtesmkdYVJBzWMsQjo5aQVT1f_WjTrlxg=w408-h544-k-no","scale":"cover","focalPoint":"center"}}]}', '2026-07-03 11:28:56.736828+07', '2026-07-03 11:28:56.736828+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('b81b8810-7455-4420-be35-cad40b26092c', '5a10eb2c-dc8f-4da8-b2f9-fe4a03c0edfa', 1, 1, 0, true, '{"title":"HẢI SẢN CÁT BÀ","subtitle":"Hương khói than hoa quyện trong từng sợi bún trắng","image":{"url":"https://cooponline.vn/tin-tuc/wp-content/uploads/2025/10/nem-cua-be-hai-phong-vo-gion-rum-nhan-cua-day-dan.png","scale":"contain","focalPoint":"100% 65%"},"description":"<p>Tinh hoa biển đảo – tươi ngon trong từng hương vị</p>","textColor":"#ffffff","textAlign":"left"}', '2026-07-03 11:28:56.736685+07', '2026-07-03 11:28:56.736685+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('a838274a-ce28-46b7-ab17-a21e3215940b', 'b33efe2f-cf38-4dcb-852f-3944dc5db52c', 8, 14, 5, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","title":"ĐẶC TRƯNG HƯƠNG VỊ & ĐIỂM CHẠM THỰC TẾ","subtitle":"\"Thưởng thức bún bò Huế là cảm nhận trọn vẹn hồn ẩm thực của vùng đất kinh kỳ.\"","items":[{"image":{"url":"https://chaca.com.vn/wp-content/uploads/2023/12/nem-cua-be.jpg","scale":"cover","focalPoint":"center"},"title":"Cảm nhận hương vị","description":"<p style=\"text-align:justify;\">Nước dùng thanh ngọt sâu từ xương hầm hòa quyện tinh tế với hương thơm nổi bật của sả và mắm ruốc xứ Huế. Màu đỏ tự nhiên từ dầu điều và dầu ớt mang lại vị cay nồng đặc trưng bùng nổ của miền Trung. Thớ thịt bò mềm mại cùng khoanh giò heo béo ngậy tương tác hoàn hảo với sợi bún to dai sần sật tạo cảm giác tròn vị hoàn chỉnh.</p>","tag":""},{"image":{"url":"https://vcdn1-dulich.vnecdn.net/2023/07/04/IMG-9865-1-1-6372-1688460337.jpg?w=1020&h=0&q=100&dpr=2&fit=crop&s=cpk-ku2FZN5iu5G-ix4bHg","scale":"cover","focalPoint":"center"},"title":"Thưởng thức","description":"<p>Thưởng thức một tô bún bò nóng hổi bốc khói ngùn ngụt ngay tại không gian trầm mặc của Huế để cảm nhận rõ nét văn hóa và hơi ấm tình người nơi đây.</p><p><strong>Khu vực đề xuất:</strong> Các tuyến phố ẩm thực gia truyền tại kinh đô xưa (đường Lý Thường Kiệt, Nguyễn Du, Bạch Đằng, thành phố Huế).</p>","tag":""}],"backgroundColor":"#fafafa"}', '2026-07-03 11:29:08.755834+07', '2026-07-03 11:29:08.755834+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('d3455248-640b-44ca-b9a6-5ce6b1a48d40', 'b33efe2f-cf38-4dcb-852f-3944dc5db52c', 1, 1, 0, true, '{"title":"BÚN BÒ HUẾ","subtitle":"Hương khói than hoa quyện trong từng sợi bún trắng","image":{"url":"/uploads/infographics/Bun-Bo-Hue-from-Huong-Giang-2011.jpg","scale":"contain","focalPoint":"100% 65%"},"description":"<p>Đậm vị cố đô – cay nồng hương sắc miền Trung</p>","textColor":"#ffffff","textAlign":"left","backgroundColor":"#850000"}', '2026-07-03 11:29:08.755692+07', '2026-07-03 11:29:08.755692+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('daa70091-2b65-4cc0-b276-d2a0496de4c9', 'b33efe2f-cf38-4dcb-852f-3944dc5db52c', 2, 3, 2, true, '{"title":"Nguồn gốc","content":"<p style=\"text-align:justify;text-align-last:right\">Có nguồn gốc từ vùng đất Huế, nơi từng là kinh đô của triều Nguyễn. Món ăn hình thành từ các làng nghề ven sông Hương, đặc biệt là làng Vân Cù (thị xã Hương Trà), nơi được xem là cái nôi của nghề làm bún truyền thống, phát triển từ món ăn dân dã thành đặc sản nổi tiếng khắp cả nước.&nbsp;</p>","image":{"url":"https://images2.thanhnien.vn/528068263637045248/2025/7/15/72b16c4518abaef5f7ba-1752552166780300358375.jpg","scale":"cover","focalPoint":"bottom"},"textAlign":"right","marginTop":-30,"marginBottom":20}', '2026-07-03 11:29:08.755796+07', '2026-07-03 11:29:08.755796+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('ecb14641-8d7d-4d22-b359-ca74cedeea7d', 'b2a66e42-ba94-4545-8214-120d5d087414', 8, 14, 3, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","title":"NGUYÊN LIỆU CHÍNH","subtitle":"","items":[{"image":{"url":"https://bizweb.dktcdn.net/100/489/006/files/pho-bo-5.jpg?v=1698658394918","scale":"cover","focalPoint":"center"},"title":"1. NƯỚC DÙNG TÍNH HOA","description":"<p>• Xương bò/gà hầm nhiều giờ.<br>• Hành, gừng nướng thơm.<br>• Quế, hồi, thảo quả, đinh hương, hạt mùi.</p>","tag":""},{"image":{"url":"https://cdn.tgdd.vn/2020/07/CookProductThumb/14-620x620-5.jpg","scale":"cover","focalPoint":"76% 44%"},"title":"2. BÁNH PHỞ TRUYỀN THỐNG","description":"<p style=\"text-align:justify;\">Những lá bánh phở làm từ gạo, thái thành sợi mềm, trắng ráo và mịn màng.</p>","tag":""},{"image":{"url":"https://cdnphoto.dantri.com.vn/-UrP8-ylieHKpuHpz8ug2YtCyXw=/thumb_w/1020/2023/06/02/tung-anh-1685639358470.jpeg","scale":"cover","focalPoint":"50% 68%"},"title":"3. THỊT TƯƠI NGON","description":"<p style=\"text-align:justify;\">• Thịt bò: Tái, chín, gầu, gân, nạm.<br>• Hoặc thịt gà tươi (đối với phở gà).</p>","tag":""},{"image":{"url":"https://cdn2.fptshop.com.vn/unsafe/800x0/rau_an_pho_1_7aa2932db9.jpg","scale":"cover","focalPoint":"center"},"title":"4. RAU & GIA VỊ KÈM","description":"Hành lá, hành tây, rau mùi, chanh, ớt, tiêu, giấm tỏi hoặc tương ớt.","tag":""}],"backgroundColor":"#fafafa"}', '2026-06-30 11:03:43.583334+07', '2026-06-30 11:03:43.583334+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('ed3133e8-12cd-4dd7-b91e-8045e259d5c7', 'b2a66e42-ba94-4545-8214-120d5d087414', 4, 6, 5, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#c35555","visibility":"all","title":"Lịch sử","steps":[{"year":"Khởi đầu","title":"Cuối TK XIX - Đầu  XX","description":"Phở hình thành tại miền Bắc và dần phổ biến ở Hà Nội"},{"year":"Thế kỷ XX","title":"Phát triển","description":"Các quán phở gia truyền phát triển mạnh, định hình phong cách phở Hà Nội với nước dùng \"trong và thanh\""},{"year":"Thế kỷ XXI","title":"Vươn tầm","description":"Bước ra thế giới, trở thành món ăn đại diện tiêu biểu cho ẩm thực Việt Nam tại hàng nghìn nhà hàng quốc tế"},{"year":"Hiện nay","title":"Đứng vững","description":"Tiếp tục là biểu tượng văn hóa lâu đời, điểm dừng chân bắt buộc của mọi du khách khi đến thủ đô"}],"backgroundColor":"#ffffff"}', '2026-06-30 11:03:43.583589+07', '2026-06-30 11:03:43.583589+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('0875f222-e762-4397-91f0-7ff865a2b2a5', '42d725c6-dd5a-42ca-acc7-d39bc6db7f49', 8, 14, 3, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","title":"Thành phần chính","subtitle":"","items":[{"image":{"url":"https://i.ytimg.com/vi/szpAajtzrhg/hq720.jpg?sqp=-oaymwEhCK4FEIIDSFryq4qpAxMIARUAAAAAGAElAADIQj0AgKJD&rs=AOn4CLDTOXAVLWbExocYFNSYu7yfCl6vGA","scale":"cover","focalPoint":"center"},"title":"XÔI VÒ THƠM DẺO","description":"<p>• Gạo nếp cái hoa vàng tinh tuyển.<br>• Đậu xanh đã cà sạch vỏ.<br>• Chút muối trắng và mỡ gà béo nhẹ</p>","tag":""},{"image":{"url":"https://thesaigontimes.vn/Uploads/Articles/99632/cde1b_dsc_6016.jpg","scale":"cover","focalPoint":"center"},"title":"CHÈ HOA CAU THANH NGỌT","description":"<p>• Đậu xanh chín tới giữ nguyên hạt.<br>• Đường phèn thanh mát.<br>• Bột sắn dây/bột năng &amp; tinh dầu hoa bưởi.</p>","tag":""}],"backgroundColor":"#fafafa"}', '2026-07-01 10:46:20.837522+07', '2026-07-01 10:46:20.837522+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('1c22d266-0ff5-4ff2-a986-2024e92e52e8', '42d725c6-dd5a-42ca-acc7-d39bc6db7f49', 4, 6, 6, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#c4bb9c","visibility":"all","title":"Lịch sử","steps":[{"year":"Thời xưa","title":"","description":"<p style=\"margin-top:-10px\">Xuất hiện trang trọng trong các mâm cỗ cúng giỗ, cưới hỏi dịp lễ Tết.</p>"},{"year":"Thế kỷ XX","title":"","description":"<p style=\"margin-top:-10px\">Trở thành thức quà quen thuộc tại các gánh hàng rong và quán chè phố cổ.</p>"},{"year":"Hiện nay","title":"","description":"<p style=\"text-align:justify;  margin-top:-10px\">Được gìn giữ trong các quán chè lâu năm và thường xuất hiện trong các sự kiện văn hóa, lễ hội ẩm thực nhằm giới thiệu nét đẹp của ẩm thực truyền thống Hà Nội.</p>"}],"backgroundColor":"#ffffff"}', '2026-07-01 10:46:20.837584+07', '2026-07-01 10:46:20.837584+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('36b01d3d-fd34-4bcd-9bf1-6a9efd603445', '42d725c6-dd5a-42ca-acc7-d39bc6db7f49', 2, 2, 2, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","title":"Nguồn gốc","content":"<p style=\"text-align:justify;\">Có lịch sử lâu đời trong văn hóa ẩm thực miền Bắc, thường xuất hiện trong các dịp lễ Tết, cưới hỏi, giỗ chạp và những mâm cỗ truyền thống. Tên gọi \"chè hoa cau\" bắt nguồn từ hình ảnh những hạt đậu xanh đã cà vỏ nổi lên trong nước chè giống những chùm hoa cau đang nở. Người Hà Nội xưa thường dùng cặp món này trong các dịp sum họp để thể hiện sự đủ đầy và hiếu khách.</p>","image":{"url":"https://images2.thanhnien.vn/zoom/1200_630/Uploaded/anhdh/2021_06_22/xoivo2cchehoacau_NKDC.jpg","scale":"cover","focalPoint":"60% 40%"},"backgroundColor":"#fffae0"}', '2026-07-01 10:46:20.837495+07', '2026-07-01 10:46:20.837495+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('50a2d4d0-3628-4691-bc23-9cbf380a3606', '42d725c6-dd5a-42ca-acc7-d39bc6db7f49', 2, 2, 1, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","title":"Giới thiệu","content":"<p style=\"text-align:justify;\">Xôi vò chè hoa cau là một cặp món truyền thống mang đậm nét thanh lịch của ẩm thực Bắc Bộ, đặc biệt quen thuộc trong đời sống văn hóa Hà Nội. Xôi vò dẻo nhưng tơi, thơm mùi đậu xanh; chè hoa cau ngọt thanh với hạt đậu vàng óng như những chùm hoa cau nở. Khi thưởng thức cùng nhau, hai món tạo nên sự hòa quyện hài hòa về hương vị và kết cấu.</p>","image":{"url":"https://file3.qdnd.vn/data/images/0/2025/09/06/upload_2083/0709thuy2.jpg?dpi=150&quality=100&w=870","scale":"cover","focalPoint":"center"},"backgroundColor":"#fffae0"}', '2026-07-01 10:46:20.837466+07', '2026-07-01 10:46:20.837466+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('86ff1d16-caf9-4a9f-86a4-11c8321aeb25', '42d725c6-dd5a-42ca-acc7-d39bc6db7f49', 1, 1, 0, true, '{"marginTop":0,"marginBottom":0,"textAlign":"right","textColor":"#fcffd6","visibility":"all","title":"XÔI VÒ CHÈ HOA CAU","description":"<p>Hai thức quà thanh tao –&nbsp;kết tinh sự tinh tế<br>trong ẩm thực Hà Thành.</p>","image":{"url":"/uploads/infographics/xoivo.jpg","scale":"contain","focalPoint":"69% 99%"},"backgroundColor":"#9ea267"}', '2026-07-01 10:46:20.837357+07', '2026-07-01 10:46:20.837357+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('909d9da6-ad3a-459a-a409-8146b5aa08a8', '42d725c6-dd5a-42ca-acc7-d39bc6db7f49', 2, 10, 5, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#ffffff","visibility":"all","content":"<p><span class=\"text-huge\"><strong>Bản sắc văn hóa</strong></span></p>","author":"Món ăn thể hiện sự khéo léo trong nghệ thuật nấu nướng của người Tràng An. Trong các dịp mâm cỗ lễ Tết, cúng tổ tiên, món ăn mang ý nghĩa cầu chúc cuộc sống đủ đầy, sung túc và gắn kết gia đình.","backgroundColor":"#d6d38a"}', '2026-07-01 10:46:20.837571+07', '2026-07-01 10:46:20.837571+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('228227db-52b3-4b5d-b603-fc463b4852e0', '78300cb2-7f07-4d18-b8d9-394ed4bcb202', 1, 1, 0, true, '{"title":"Bánh Cuốn Thanh Trì","subtitle":"Tinh tế từ lớp vỏ mỏng tang, thơm hương nhân thịt nấm","image":{"url":"/uploads/infographics/banhcuon1.jpg","scale":"contain","focalPoint":"0% 32%"},"description":"Mỏng như lụa – thanh vị ngàn năm, tinh hoa ẩm thực Hà Thành.","textAlign":"right","backgroundColor":"#d28156"}', '2026-07-02 19:37:21.72217+07', '2026-07-02 19:37:21.722171+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('191a49e1-5cfa-4bce-9919-a90c16d709af', 'fa85608a-62d6-4524-a0e7-3a380897f7d0', 2, 16, 6, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","title":"Gợi ý quán ngon","restaurants":[{"name":"Bánh đa cua Cụ Cầu","address":"39 P. Kỳ Đồng, Hồng Bàng","mapUrl":"https://maps.app.goo.gl/QSG1RpdwqCT13aex8","image":{"url":"https://lh3.googleusercontent.com/gps-cs-s/APNQkAGE8qpsvccfTbIt05c2P35c9wJj7ZuIMa0rhmHJLb8qe5gzvR_u3z2-D8vhv3ykEDVmhbESEqGsJRoA_DP0GTzKhFcNRpF7hdM-fXJYH5EJw3qMPNyx0HHv4vnCPw5hzXmmMU5t=w408-h306-k-no","scale":"cover","focalPoint":"center"}},{"name":"Bánh đa cua cô Thanh","address":"89b P. Đinh Tiên Hoàng, Hồng Bàng","mapUrl":"https://maps.app.goo.gl/oWwYfBX6QAsFZ4KXA","image":{"url":"https://lh3.googleusercontent.com/gps-cs-s/APNQkAF9PTSnXvFlKHAs38aPSTqRT-o311dZ-wporPWp4U8w7L9cK2hvZrKYFzzZorUbXMx0SSlQg1cT9clsJceu7Q-7YQ0nwrIwoxXdgt_VJmECiNfMaInIthDuerY1eDwnFxN5JJXw77D9CLAi=w426-h240-k-no","scale":"cover","focalPoint":"center"}},{"name":"Bánh đa cua cô Hồng","address":"2 Phạm Ngũ Lão, Gia Viên","mapUrl":"https://maps.app.goo.gl/8uyxXAHu3xcpQMhv5","image":{"url":"https://lh3.googleusercontent.com/gps-cs-s/APNQkAFemmhN6b-4HsXD9rwxwMmsM-5zdhkVbjIKxrNTGazqZVlAmgyNot-mg-CebQTYinYMP5CSIEro-27MIRjIpSsiGYUNejz9aaa5zOJb6zt0ujoNP3UNeVfQ5t8q_g31dlT_2zVDhSRFOm3_=w408-h544-k-no","scale":"cover","focalPoint":"center"}}]}', '2026-07-02 20:03:40.584764+07', '2026-07-02 20:03:40.584764+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('1e797bb4-3039-4680-8da6-1d603aaa2be9', 'fa85608a-62d6-4524-a0e7-3a380897f7d0', 8, 14, 5, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","title":"ĐẶC TRƯNG HƯƠNG VỊ & ĐIỂM CHẠM THỰC TẾ","subtitle":"\"Muốn cảm nhận hương vị đất Cảng, hãy bắt đầu bằng một bát bánh đa cua nóng hổi.\"","items":[{"image":{"url":"https://danviet-24h.ex-cdn.com/files/upload/2-2021/images/2021-04-09/2-1617987082-425-width1600height1200.jpg","scale":"cover","focalPoint":"center"},"title":"Cảm nhận hương vị","description":"<p style=\"text-align:justify;\">Nước dùng ngọt tự nhiên từ cua đồng và xương hầm hòa quyện vị béo ngậy của riêu cua mềm mịn. Sợi bánh đa đỏ dai sần sật tương tác hoàn hảo với miếng chả lá lốt đậm đà thơm tiêu. Các loại rau muống chẻ, rau rút tạo cảm giác tươi mát, mang đến sự kết hợp hài hòa giữa sự dân dã đồng quê và hương vị lộng gió của vùng biển.</p>","tag":""},{"image":{"url":"https://cdn.smarttravel.vn/files/2021/04/05/Ninh%20Thu%E1%BA%ADn/banh-da-cua-14-1595870211-9981.jpeg","scale":"cover","focalPoint":"center"},"title":"Thưởng thức tại quán","description":"<p>Thưởng thức trực tiếp ngay tại các quán nhỏ nghi ngút khói ven đường Hải Phòng để đảm bảo sợi bánh đa đạt độ dai chuẩn và rau muống chẻ giữ nguyên vị giòn xanh</p>\n<p><strong>Khu vực đề xuất:</strong> Các tuyến phố ẩm thực lâu đời tại đất Cảng (đường Lạch Tray, Cầu Đất, Trần Quang Khải).</p>","tag":""}],"backgroundColor":"#fafafa"}', '2026-07-02 20:03:40.584753+07', '2026-07-02 20:03:40.584754+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('5aa6be5d-c5dc-4319-9f50-4916d72521bc', 'fa85608a-62d6-4524-a0e7-3a380897f7d0', 8, 14, 4, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","title":"NGUYÊN LIỆU CHÍNH","subtitle":"","items":[{"image":{"url":"https://sieuthiandam.com/wp-content/uploads/2018/07/banh-da-kho-vifon-goi-300g-202008062030135951.jpg","scale":"cover","focalPoint":"center"},"title":"BÁNH ĐA ĐỎ","description":"<p>• Làm hoàn toàn từ gạo.<br>• Màu nâu đỏ đặc trưng tự nhiên từ mật mía/gấc.<br>• Sợi dai, dày và săn khi chan nước.</p>","tag":""},{"image":{"url":"https://static.vinwonders.com/production/banh-da-cua-hai-phong-18.jpg","scale":"cover","focalPoint":"58% 51%"},"title":"NƯỚC DÙNG NGỌT THANH","description":"<p>• Cua đồng tươi giã nhuyễn lọc lấy nước.<br>• Kết hợp xương ống hầm sâu.<br>• Cà chua và gạch cua chưng phi hành thơm béo.</p>","tag":""},{"image":{"url":"https://static.vinwonders.com/production/banh-da-cua-hai-phong-6.jpg","scale":"cover","focalPoint":"55% 0%"},"title":"TOPPING PHONG PHÚ","description":"<p>• Riêu cua bùi béo.<br>• Chả lá lốt rán vàng, chả cá giòn.<br>• Tôm tươi, bề bề (tôm tích), thịt bò hoặc giò.</p>","tag":""},{"image":{"url":"https://www.lorca.vn/wp-content/uploads/2023/07/Buoc-3-3-3466-1677318715.jpg","scale":"cover","focalPoint":"center"},"title":"RAU ĂN KÈM","description":"<p>• Rau muống chẻ giòn xanh.<br>• Rau rút thanh mát.<br>• Hành lá và hành phi tự chao vàng rụm</p>","tag":""}],"backgroundColor":"#fafafa"}', '2026-07-02 20:03:40.584744+07', '2026-07-02 20:03:40.584744+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('ad758acf-9a3e-43dc-a04b-d87f4d45f12a', 'fa85608a-62d6-4524-a0e7-3a380897f7d0', 1, 1, 0, true, '{"title":"BÁNH ĐA CUA","subtitle":"Tinh tế từ lớp vỏ mỏng tang, thơm hương nhân thịt nấm","image":{"url":"/uploads/infographics/Banh-da-cua-Hai-Phong-7-1080x600.jpeg","scale":"contain","focalPoint":"0% 32%"},"description":"Sợi bánh đỏ đậm tình đất Cảng – đậm đà hương vị biển","textAlign":"right","backgroundColor":"#d28156"}', '2026-07-02 20:03:40.584582+07', '2026-07-02 20:03:40.584582+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('f3e0a5be-f0e5-47db-8307-c8cb27830abb', 'fa85608a-62d6-4524-a0e7-3a380897f7d0', 2, 3, 2, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","title":"Nguồn gốc","content":"<p style=\"text-align:justify;\">Bắt nguồn từ Hải Phòng – thành phố cảng lớn nhất miền Bắc, nơi có truyền thống kết hợp nguyên liệu đồng quê với hải sản địa phương. Ban đầu, món ăn phục vụ bữa ăn hằng ngày của người lao động. Theo thời gian, bánh đa cua được bổ sung nhiều loại topping phong phú, trở thành một trong những đặc sản nổi tiếng nhất và là món ăn không thể bỏ lỡ đối với du khách.</p>","image":{"url":"https://danviet.ex-cdn.com/files/f1/296231569849192448/2023/7/23/1f304d8530dee380bacf-16898756330671590884937-1690078092831-1690078093089695988383.jpg","scale":"cover","focalPoint":"center"},"backgroundColor":"#ffffff"}', '2026-07-02 20:03:40.584723+07', '2026-07-02 20:03:40.584723+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('f5ea4f89-6a62-4259-adad-ea48614b183f', 'fa85608a-62d6-4524-a0e7-3a380897f7d0', 4, 6, 3, true, '{"paddingTop":40,"paddingBottom":40,"textAlign":"left","textColor":"#743e3e","visibility":"all","title":"LỊCH SỬ & DẤU MỐC NỔI BẬT","steps":[{"year":"Cuối thế kỷ XIX","title":"Xuất hiện","description":"tại các khu phố cổ Hà Nội sầm uất."},{"year":"Thế kỷ XX","title":"Phổ biến","description":"Trở thành món ăn phổ biến trong đời sống người dân thủ đô."},{"year":"Thế kỷ XXI","title":"Thế mạnh","description":"Trở thành đặc sản nổi tiếng, vươn rộng đến nhiều tỉnh thành và các nhà hàng Việt Nam."},{"year":"Hiện nay","title":"Vị thế","description":"Là món ăn biểu tượng, xuất hiện trang trọng trong các cẩm nang du lịch quốc tế."}],"backgroundColor":"#ffffff","marginTop":0,"marginBottom":0}', '2026-07-02 20:03:40.584735+07', '2026-07-02 20:03:40.584735+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('e5da61e7-013e-43ab-9e7f-453ef91bd511', 'b33efe2f-cf38-4dcb-852f-3944dc5db52c', 2, 2, 1, true, '{"title":"Giới thiệu","content":"<p style=\"text-align:justify;\">Bún bò Huế là một trong những món ăn nổi tiếng nhất của ẩm thực Việt Nam, mang đậm dấu ấn của vùng đất cố đô. Với nước dùng đậm đà, thơm mùi sả và mắm ruốc Huế, kết hợp cùng thịt bò, giò heo và sợi bún to đặc trưng, món ăn chinh phục thực khách bằng sự cân bằng giữa vị cay, ngọt và thơm, tạo nên trải nghiệm khó quên.</p>","image":{"url":"https://i.ytimg.com/vi/CSI9ildGX9s/maxresdefault.jpg","scale":"contain","focalPoint":"center"},"marginTop":0,"marginBottom":20}', '2026-07-03 11:29:08.755771+07', '2026-07-03 11:29:08.755771+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('330084a2-b1f8-4125-9dbd-3549927bf0e0', 'b33efe2f-cf38-4dcb-852f-3944dc5db52c', 4, 6, 4, true, '{"paddingTop":40,"paddingBottom":40,"textAlign":"left","textColor":"#743e3e","visibility":"all","title":"LỊCH SỬ & DẤU MỐC NỔI BẬT","steps":[{"year":"Thời Nguyễn","title":"Hình thành ","description":"Tại vùng đất cố đô, gắn chặt với gách nghề của các làng làm bún cổ truyền."},{"year":"Thế kỷ XX","title":"Phổ biến","description":"Rộng khắp miền Trung, các quán ăn gia truyền xuất hiện lưu giữ bí quyết riêng."},{"year":"Thế kỷ XXI","title":"Nổi tiếng","description":"Bước ra thế giới, vươn tầm đỉnh cao và có mặt tại hàng nghìn nhà hàng ở nhiều quốc gia."},{"year":"Hiện nay","title":"Vị thế","description":"Là biểu tượng ẩm thực bất biến của Huế, thường xuyên lọt top món ăn tiêu biểu của châu Á."}],"backgroundColor":"#ffffff","marginTop":0,"marginBottom":0}', '2026-07-03 11:29:08.755821+07', '2026-07-03 11:29:08.755821+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('092761f5-c3ce-459b-90be-257681b0876c', '74529105-6b93-417d-a764-f8b905556bcd', 2, 17, 6, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#318caa","visibility":"all","topText":"<h2><strong>Cảm nhận hương vị</strong></h2><p style=\"text-align:justify;\">Độ tươi ngon tuyệt đối nhờ được đánh bắt và chế biến ngay trong ngày. Thớ thịt săn chắc, giữ vị ngọt sâu tự nhiên đượm hương vị biển đậm đà mà không hề tanh. Ẩm thực nơi đây hạn chế sử dụng gia vị cầu kỳ, tôn vinh nguyên bản chất lượng của hải sản biển sâu.</p>","image":{"url":"https://sun-ecommerce-cdn.azureedge.net/ecommerce/service-sites/asset/SunWorldCatBa/swold/hai-san-cat-ba-11-dia-diem-an-mua-ve-ngon-kem-gia-review-5704/goi-y-mot-so-dia-chi-nha-hangquan-an-hai-san-ngon-o-cat-ba.jpg","scale":"cover","focalPoint":"center"},"bottomText":"<h2>Thưởng thức tại quán</h2><p>Thưởng thức hải sản trực tiếp trên các nhà hàng nổi, bè nuôi hoặc quán ăn ven biển để cảm nhận trọn vẹn vị ngọt đại dương hòa cùng làn gió mặn và tiếng sóng vỗ.</p><p>&nbsp;</p><p><strong>Khu vực đề xuất:</strong> Các nhà hàng làng chài, lồng bè nổi quanh đảo Cát Bà, vịnh Lan Hạ, Hải Phòng.</p>","backgroundColor":"#ffffff"}', '2026-07-03 10:50:14.305399+07', '2026-07-03 10:50:14.305399+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('284eca7e-4723-45d5-a2db-1b441a20e98f', '74529105-6b93-417d-a764-f8b905556bcd', 8, 14, 3, true, '{"marginTop":0,"marginBottom":0,"textAlign":"center","textColor":"#333333","visibility":"all","title":"CÁC LOẠI HẢI SẢN","subtitle":"","items":[{"image":{"url":"https://tourcatba.com.vn/wp-content/uploads/2026/02/anhminhhoa-2026-03-04T211758.923.jpg","scale":"cover","focalPoint":"center"},"title":"TU HÀI CÁT BÀ","description":"Còn được gọi là Ốc vòi voi, \"Vua hải sản Cát Bà\" với thớ thịt dày, ngọt và giòn sần sật","tag":""},{"image":{"url":"https://vinhlanha.com/wp-content/uploads/2020/08/Sam-bien-nuong.jpg","scale":"cover","focalPoint":"center"},"title":"SAM BIỂN","description":"<p>Độc đáo với nhiều cách biến tấu: gỏi sam, nướng, xào chua ngọt.</p>","tag":""},{"image":{"url":"https://file.hstatic.net/1000030244/article/be-be-lam-mon-gi-ngon-1_d4e67dc8bcdf4538b4fe0a0b3907cabb.jpg","scale":"cover","focalPoint":"center"},"title":"BỀ BỀ THỊT CHẮC","description":"Phần thịt săn chắc, đậm vị biển, thường rang muối hoặc hấp.","tag":""},{"image":{"url":"https://cdnv2.tgdd.vn/bhx-static/bhx/News/Images/2025/11/12/1585565/image8_202511120022282960.jpg","scale":"cover","focalPoint":"center"},"title":"CÁ SONG TRÂN QUÝ","description":"Thớ thịt trắng muốt, săn chắc, ngọt thơm khi hấp xì dầu.","tag":""}],"backgroundColor":"#fafafa"}', '2026-07-03 10:50:14.305376+07', '2026-07-03 10:50:14.305376+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('93aa12df-1da3-402c-a261-8c53ce3b33d7', '74529105-6b93-417d-a764-f8b905556bcd', 2, 3, 2, true, '{"title":"Nguồn gốc","content":"<p style=\"text-align:justify;\">Quần đảo Cát Bà gồm hơn 360 hòn đảo lớn nhỏ nằm ở cửa ngõ vịnh Bắc Bộ. Từ hàng trăm năm trước, cư dân trên đảo đã sinh sống bằng nghề đánh bắt và nuôi trồng thủy sản, hình thành nên nền văn hóa biển đặc sắc. Với hệ sinh thái biển đa dạng và vùng nước giàu dinh dưỡng, nơi đây đã tạo nên một thương hiệu ẩm thực nổi tiếng của đất Cảng.</p>","image":{"url":"https://i-giadinh.vnecdn.net/2024/12/26/Thanhpham11-1735198211-1599-1735198217.jpg","scale":"cover","focalPoint":"bottom"},"textAlign":"right","marginTop":-30,"marginBottom":20}', '2026-07-03 10:50:14.305363+07', '2026-07-03 10:50:14.305363+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('9ea9fec3-fced-4bee-abb6-ec63a4baa1ca', '74529105-6b93-417d-a764-f8b905556bcd', 2, 16, 7, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","title":"Gợi ý quán ngon","restaurants":[{"name":"Nhà hàng Vũ Dương","address":"45 Tùng Dinh, Cát Hải","mapUrl":"https://maps.app.goo.gl/8X3hVw7jeqoL3wyGA","image":{"url":"https://lh3.googleusercontent.com/gps-cs-s/APNQkAEf15dhdSHHKqsrj8F3uvufjseSIjxvEQU32a7FYASjxCCxTn7F7OBYpG6OMFBpnzpMtEZ3_g-4df0IJRngVphCvWalsiOQYVj94DnOw4P7UVAx0npTr6YLrFKHzWvONq7fqXL49w=w408-h408-k-no","scale":"cover","focalPoint":"48% 100%"}},{"name":"Quân Cát Bà","address":"180 Một Tháng Tư, Cát Hải","mapUrl":"https://maps.app.goo.gl/xW3coq7Af1PLCA1m6","image":{"url":"https://lh3.googleusercontent.com/gps-cs-s/APNQkAEzY2Y5YCNKg7vMMcjW8B7laQB0nrEaUsZZ_1JGj8nyMRnwmAbrkoDqcatNB_DHH92TlIbNIzqt7Y65nxn4M4HR5E_ZeDbGJHKleZPEJTEk17Lf9PM_CNtevE3QmZLAY8bI-60=w426-h240-k-no","scale":"cover","focalPoint":"49% 42%"}},{"name":"Buffet Hải Sản Ốc Ba Tàu","address":"29 Tùng Dinh, Cát Hải","mapUrl":"https://maps.app.goo.gl/1djsCGVTcMccWixn6","image":{"url":"https://lh3.googleusercontent.com/gps-cs-s/APNQkAFZUXYyw_YkKi5Q5UfcfCcrS83Fx1y9vKhbd3G2xPX4Zufpx46tgRoSLbPC-U5E9tgtvfZ2WS7222JOT5bJBjb4FxKmG_RaxhEb4DiF2CMHZLKei80z_EWqJbyvvhvsr6V8rfh_uDYAtuPl=w408-h271-k-no","scale":"cover","focalPoint":"center"}}]}', '2026-07-03 10:50:14.305433+07', '2026-07-03 10:50:14.305433+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('a6bd3708-ea53-4c0e-a7fa-47ac68009580', '74529105-6b93-417d-a764-f8b905556bcd', 1, 1, 0, true, '{"title":"NEM CUA BỂ","subtitle":"Hương khói than hoa quyện trong từng sợi bún trắng","image":{"url":"/uploads/infographics/an-hai-san-o-cat-ba-tuoi-ngon.jpg","scale":"contain","focalPoint":"100% 65%"},"description":"<p>Giòn rụm vỏ vàng – trọn vị biển khơi trong từng miếng nem</p>","textColor":"#ffffff","textAlign":"left"}', '2026-07-03 10:50:14.304997+07', '2026-07-03 10:50:14.304998+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('09707df9-1037-4d8b-a081-f432806faceb', 'a1387f5f-fe3e-4783-addb-83f3bb58d93d', 1, 1, 0, true, '{"title":"Bún Chả Hà Nội","subtitle":"Hương khói than hoa quyện trong từng sợi bún trắng","image":{"url":"https://vcdn1-vnexpress.vnecdn.net/2021/08/13/f09c9635-f2fc-4d3f-88ca-f933aa-8187-6754-1628833865.jpg?w=680&h=0&q=100&dpr=2&fit=crop&s=jngHyQ9zO2qLz4zJC1JDkw","scale":"contain","focalPoint":"100% 65%"},"description":"<p>Hương than hoa quyện vị nước mắm – tinh hoa<br/> ẩm thực đất kinh kỳ.</p>","textColor":"#ffffff","textAlign":"left"}', '2026-07-03 21:14:29.12992+07', '2026-07-03 21:14:29.129957+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('b1e4a7af-2281-4bf2-a0e6-eb3f7791d832', '74529105-6b93-417d-a764-f8b905556bcd', 4, 6, 5, true, '{"paddingTop":40,"paddingBottom":40,"textAlign":"left","textColor":"#743e3e","visibility":"all","title":"LỊCH SỬ & DẤU MỐC NỔI BẬT","steps":[{"year":"Truyền thống","title":"Biển khơi đầy cá","description":"Cư dân bám biển, hình thành văn hóa đánh bắt thủy sản từ nhiều thế hệ"},{"year":"Cuối thế kỷ XX","title":"Du lịch","description":"Du lịch đảo cất cánh, các nhà hàng hải sản và làng bè nổi tiếng bắt đầu định hình."},{"year":"Thế kỷ XXI","title":"Nổi tiếng","description":"Trở thành trung tâm du lịch biển lớn của miền Bắc, hải sản vang danh cả nước."},{"year":"Hiện nay","title":"Vị thế","description":"Thương hiệu ẩm thực đỉnh cao, điểm chạm hút hàng triệu du khách mỗi năm."}],"backgroundColor":"#ffffff","marginTop":0,"marginBottom":0}', '2026-07-03 10:50:14.305392+07', '2026-07-03 10:50:14.305392+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('ca7f5c67-b991-4331-9b57-575ef3038afa', '74529105-6b93-417d-a764-f8b905556bcd', 2, 2, 1, true, '{"title":"Giới thiệu","content":"<p style=\"text-align:justify;\">Nằm giữa quần đảo tuyệt đẹp của vịnh Bắc Bộ, Cát Bà không chỉ nổi tiếng với cảnh quan thiên nhiên mà còn được biết đến là \"thiên đường hải sản\" của Hải Phòng. Nhờ nguồn hải sản phong phú, môi trường biển trong lành và nghề đánh bắt truyền thống lâu đời, hải sản Cát Bà mang hương vị tươi ngon đặc trưng, trở thành trải nghiệm ẩm thực không thể bỏ lỡ khi đặt chân đến hòn đảo này.</p>","image":{"url":"https://haisankhocatba.com/wp-content/uploads/2025/06/ban-hai-san-tai-cat-ba.jpg","scale":"contain","focalPoint":"center"},"marginTop":0,"marginBottom":20}', '2026-07-03 10:50:14.305287+07', '2026-07-03 10:50:14.305288+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('f408e7e0-fb61-4218-99c5-e1674ec81ced', '74529105-6b93-417d-a764-f8b905556bcd', 8, 14, 4, true, '{"marginTop":-50,"marginBottom":0,"textAlign":"center","textColor":"#333333","visibility":"all","title":"","subtitle":"","items":[{"image":{"url":"https://scontent-sin2-2.xx.fbcdn.net/v/t39.30808-6/719770352_4043714845764157_8900718002385285939_n.jpg?stp=dst-jpg_tt6&cstp=mx1536x2048&ctp=s590x590&_nc_cat=103&ccb=1-7&_nc_sid=833d8c&_nc_ohc=xxjRB9ZelZQQ7kNvwECcF9b&_nc_oc=AdqBYQhOPXE3lUwqFnaNuW9MvvOl4sUT-ThWjfGqJohSLZgMm_QDh23QzoU3OQawAMaOpusyVV102T4QV1cNUKhD&_nc_zt=23&_nc_ht=scontent-sin2-2.xx&_nc_gid=XKg8V-oSyQ87ZZlBIuv6mg&_nc_ss=7b2a8&oh=00_AQD7zHQsWjKAjGk_H7jibsHILbm4jUhDPABeI0NINBr3DA&oe=6A4CEDF4","scale":"cover","focalPoint":"center"},"title":"MỰC TƯƠI TỰ NHIÊN","description":"Giữ trọn độ giòn sần sật và vị ngọt tự nhiên khi nướng hoặc hấp","tag":""},{"image":{"url":"https://vuonquocgiacatba.com.vn/wp-content/uploads/2025/03/Am-thuc-Cat-Ba.jpg","scale":"cover","focalPoint":"center"},"title":"HÀU SỮA","description":"<p>Tươi ngon, béo ngậy, mang lại hương vị biển cả trọn vẹn.</p>","tag":""},{"image":{"url":"https://vinhlanha.com/wp-content/uploads/2020/08/ran-bien-cat-ba-1.jpg","scale":"cover","focalPoint":"center"},"title":"RẮN BIỂN","description":"<p>Món ăn đặc biệt, hầm thuốc bắc hoặc nướng giúp bồi bổ sức khỏe.</p>","tag":""}],"backgroundColor":"#fafafa"}', '2026-07-03 10:50:14.305385+07', '2026-07-03 10:50:14.305385+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('5df04c54-4b06-4dd4-8b06-1fbcb37d0c4f', 'a1387f5f-fe3e-4783-addb-83f3bb58d93d', 8, 14, 6, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","title":"HƯƠNG VỊ, TRẢI NGHIỆM & GIÁ TRỊ VĂN HÓA","subtitle":"\"Tinh hoa đất kinh kỳ gói trọn trong làn khói than hoa và bát nước chấm đậm đà.\"","items":[{"image":{"url":"/uploads/infographics/buncha3-8d60d66eaa444ead9e04550b3b74251c.jpg","scale":"cover","focalPoint":"center"},"title":"Đặc trưng hương vị","description":"<p style=\"text-align:justify;\">Mùi thơm quyến rũ từ khói than hoa. Thịt mềm, đậm vị, hơi cháy cạnh hòa quyện với nước chấm thanh nhẹ nhưng đậm đà. Rau thơm tạo cảm giác tươi mát, cân bằng vị giác hoàn hảo.</p>","tag":""},{"image":{"url":"/uploads/infographics/buncha4-7511040337ba4c70b8c36cae50dee339.jpg","scale":"cover","focalPoint":"center"},"title":"Giá trị văn hóa","description":"Phản ánh nét tinh tế, phong cách sống thanh lịch của người Tràng An: không cầu kỳ nhưng chú trọng hương vị, sự chỉn chu và trải nghiệm thưởng thức.","tag":""}],"backgroundColor":"#fafafa"}', '2026-07-03 21:14:29.160554+07', '2026-07-03 21:14:29.160554+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('7c5c7750-bafe-4e39-9a11-13174039a996', 'a1387f5f-fe3e-4783-addb-83f3bb58d93d', 5, 7, 4, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","title":"","description":"","images":[{"url":{"url":"/uploads/infographics/obamabuncha3-e774623f560f40a382b685a222819e00.jpg","scale":"fill","focalPoint":"bottom"},"alt":""}],"backgroundColor":"#ffffff"}', '2026-07-03 21:14:29.160469+07', '2026-07-03 21:14:29.160469+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('9236051c-494a-4124-8407-03d2c9cb7a7d', 'a1387f5f-fe3e-4783-addb-83f3bb58d93d', 8, 14, 5, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","title":"NGUYÊN LIỆU CHÍNH","subtitle":"","items":[{"image":{"url":"/uploads/infographics/bun-tuoi-soi-lon-6e0c14a39edd4487af47b05b25651198.jpg","scale":"cover","focalPoint":"center"},"title":"1. BÚN TƯƠI","description":"Sợi bún trắng mềm, thanh vị, được làm từ gạo tinh tuyển.","tag":""},{"image":{"url":"/uploads/infographics/images-05ff39c99e224f25a48c46c7b8a4fafd.jpg","scale":"cover","focalPoint":"center"},"title":"2. THỊT NƯỚNG","description":"• Thịt ba chỉ thái lát<br/>\n• Thịt nạc vai băm viên<br/>\n• Ướp gia vị truyền thống<br/>","tag":""},{"image":{"url":"/uploads/infographics/images-(1)-4d1e3bc452dc47db8bec100005f6cec3.jpg","scale":"cover","focalPoint":"center"},"title":"3. NƯỚC CHẤM","description":"Hòa quyện tinh tế giữa: Nước mắm pha, giấm/chanh, đường, tỏi, ớt.","tag":""},{"image":{"url":"/uploads/infographics/Buoc-3-3-6050-1681636163-0a12c38674114e029aca9606342e2cca.jpg","scale":"cover","focalPoint":"center"},"title":"4. RAU ĂN KÈM","description":"Xà lách, kinh giới, tía tô, húng láng và rau thơm theo mùa.","tag":""}],"backgroundColor":"#fafafa"}', '2026-07-03 21:14:29.160512+07', '2026-07-03 21:14:29.160512+07');
