Nội, Hoàn Kiếm, Hà Nội","mapUrl":"https://www.google.com/maps/place/B%C3%BAn+ch%E1%BA%A3+41+C%E1%BB%ADa+%C4%90%C3%B4ng/@21.0345364,105.8459423,17z/data=!3m1!4b1!4m6!3m5!1s0x3135ab004dc0c117:0xb5c19abbc1a62922!8m2!3d21.0345364!4d105.8459423!16s%2Fg%2F11wq8m_61m?entry=ttu&g_ep=EgoyMDI2MDYyMy4wIKXMDSoASAFQAw%3D%3D","image":{"url":"https://lh3.googleusercontent.com/gps-cs-s/APNQkAFIdhQRmMryQRHVeLf6P5pW--OqNoaxEBF2yZ0t8Vu2uMJfC0n1yHjQLasp_2Cs-Ri1M54Que964jvpKzvKukC3hjR3_CPkhrsVx0ODiKKng_2brzMpoHslHOliKrPoGkKESGSUCHr5OsM=w408-h544-k-no","scale":"cover","focalPoint":"center"}}],"title":"ĐỊA CHỈ QUÁN NGON GIA TRUYỀN"}', '2026-07-03 21:14:29.160594+07', '2026-07-03 21:14:29.160594+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('92c6a5c5-8dac-4492-a230-25d248a7ceea', 'a1387f5f-fe3e-4783-addb-83f3bb58d93d', 2, 2, 1, true, '{"title":"Giới thiệu","content":"<p>Bún chả Hà Nội là một trong những món ăn tiêu biểu của thủ đô ngàn năm văn hiến. Sự kết hợp giữa thịt lợn nướng thơm lừng trên than hoa, nước chấm chua ngọt đậm đà và bún tươi mềm mại đã tạo nên một hương vị khó quên đối với thực khách trong và ngoài nước.</p>","image":{"url":"/uploads/infographics/buncha7-6cc90a66f02f4b5eb5acbe4679c7874e.jpg","scale":"contain","focalPoint":"center"},"marginTop":0,"marginBottom":20}', '2026-07-03 21:14:29.159946+07', '2026-07-03 21:14:29.159946+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('b3ec30c0-db76-45c6-8163-427a1869a263', 'a1387f5f-fe3e-4783-addb-83f3bb58d93d', 2, 3, 2, true, '{"title":"Nguồn gốc","content":"<p style=\"text-align: justify; text-align-last: right;\">Xuất hiện từ cuối thế kỷ XIX và đầu thế kỷ XX tại khu vực phố cổ, gắn liền với nhịp sống của người dân thủ đô từ những gánh hàng rong ven phố đến các quán ăn gia truyền.</p>","image":{"url":"/uploads/infographics/buncha8-c41e6c46c9de44fc9b929e1d9cd85451.jpg","scale":"cover","focalPoint":"bottom"},"textAlign":"right","marginTop":-30,"marginBottom":20}', '2026-07-03 21:14:29.160337+07', '2026-07-03 21:14:29.160337+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('fd40871a-5d79-4eca-bcfa-64e33a8fb3a7', 'a1387f5f-fe3e-4783-addb-83f3bb58d93d', 4, 6, 3, true, '{"paddingTop":40,"paddingBottom":40,"textAlign":"left","textColor":"#743e3e","visibility":"all","title":"LỊCH SỬ & DẤU MỐC NỔI BẬT","steps":[{"year":"Đầu thế kỷ XX","title":"Xuất hiện","description":"trong đời sống với nguyên liệu cua đồng mộc mạc phục vụ người lao động."},{"year":"Giữa thế kỷ XX","title":"Phổ biến","description":"khắp thành phố, các quán ăn gia truyền ra đời lưu giữ bí quyết nấu nước dùng."},{"year":"Giữa thế kỷ XX","title":"Sự kiện \"Cột mốc Vàng\"","description":"Tổng thống Barack Obama và đầu bếp Anthony Bourdain thưởng thức bún chả tại phố Lê Văn Hưu."},{"year":"Hiện nay","title":"Vị thế","description":"Là một trong những món ăn Việt Nam nổi tiếng nhất trên bản đồ ẩm thực thế giới."}],"backgroundColor":"#ffffff","marginTop":0,"marginBottom":0}', '2026-07-03 21:14:29.160407+07', '2026-07-03 21:14:29.160407+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('09746278-6dd2-464c-a6c5-424c1f00aac9', '1f2034c5-0aa6-4674-924f-7a7f420ea219', 4, 6, 6, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","title":"Lịch sử","steps":[{"year":"Thời Xưa","title":"Các gánh chè rong ","description":"Xuất hiện khắp phố phường phục vụ người dân."},{"year":"Thế kỷ XX","title":"Phổ biến","description":"Nhiều quán chè gia truyền ra đời, lưu giữ công thức cổ truyền."},{"year":"Hiện nay","title":"","description":"<p style=\"margin-top: -10px;\">Phát triển biến tấu hiện đại, là điểm dừng chân của du khách.</p>"}],"backgroundColor":"#ffffff"}', '2026-07-03 21:14:40.31801+07', '2026-07-03 21:14:40.31801+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('0d8ef251-015c-461d-b687-b7f9309e9c8e', '1f2034c5-0aa6-4674-924f-7a7f420ea219', 2, 16, 8, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#a86200","visibility":"all","title":"Quán chè ngon tại Hà Nội","restaurants":[{"name":"Xôi chè bà Thìn","address":"1 P. Bát Đàn, Phố cổ Hà Nội, Hoàn Kiếm","mapUrl":"https://maps.app.goo.gl/L5evZGCMB4WE7yyr6","image":{"url":"https://lh3.googleusercontent.com/gps-cs-s/APNQkAEWF4OeyTYEQYWRiCNLXByNNEnwK9qRwz_-QAkpQhCNr7X6rtt69_wvCZKRm-yRSSnMJOf3lLsUfWTP15-tQ0Cba0TqOa94HHNzaCemDaxPT8j4b1zrDXRLPDjCGsnhYPmkbkQg_gYZYoIv=w408-h544-k-no","scale":"cover","focalPoint":"center"}},{"name":"Chè Mười Sáu","address":"21A P. Lò Đúc, Hai Bà Trưng","mapUrl":"https://maps.app.goo.gl/L5ED6Z3FXUAHtupd6","image":{"url":"https://lh3.googleusercontent.com/gps-cs-s/APNQkAFw_spTruRlh250hpzgwzVKpDlfnnIMTBnLTyybJljInsU5cDGpsCAUdEzdO-mzpdKps-cvB7Wkkxzs1ZcAo8gtcHEprD92wv2k7vSSXqBglx7_RZipDLi5mLGp_Q9gwGiD6TuHSA=w408-h408-k-no","scale":"cover","focalPoint":"center"}},{"name":"Chè Ngon 93","address":"85 P. Hàng Bạc, Phố cổ Hà Nội, Hoàn Kiếm","mapUrl":"https://maps.app.goo.gl/qsTcaorBuNfxHWgw7","image":{"url":"https://lh3.googleusercontent.com/gps-cs-s/APNQkAFC9vxOcfJ1PoIhHY6gxZKB4n0yhwLqmVFnfGc2eHvVrtHea05EN5MD3zANMx9lFu4FU5PegIMSzPiv51ou__PmLHXTSNum3gE5DCD_T3jDK6DOZyr2HjEuhYbkvOvrp-SqhOGkMKa5GcjK=w426-h240-k-no","scale":"cover","focalPoint":"center"}}],"backgroundColor":"#f5e4d1"}', '2026-07-03 21:14:40.318058+07', '2026-07-03 21:14:40.318058+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('4005f04f-d7c9-4e5b-8665-a43b65f5bc98', '1f2034c5-0aa6-4674-924f-7a7f420ea219', 2, 17, 5, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","topText":"<h2 style=\"text-align:justify;\">Đặc trưng hương vị &amp; Trải nghiệm</h2><p style=\"text-align:justify;\">Vị ngọt thanh không gắt, hương thơm tự nhiên từ đậu, hạt sen hay gừng. Một bát chè mát lạnh giữa ngày hè hay bát chè nóng trong tiết trời se lạnh đem lại cảm giác ngồi bên quán nhỏ phố cổ, ngắm dòng người qua lại bình dị.ên</p>","image":{"url":"https://static.vinwonders.com/production/che-ngon-ha-noi-0.jpg","scale":"cover","focalPoint":"center"},"bottomText":"<h2 style=\"text-align:right;\">Giá trị văn hóa</h2><p style=\"text-align:justify; text-align-last: right;\">Phản ánh phong cách sống thanh lịch của người Tràng An. Các món chè cổ truyền (chè kho, chè bà cốt) gắn liền với dịp lễ, Tết, cúng gia tiên, thể hiện nét đẹp trong văn hóa ẩm thực và tín ngưỡng.</p>","backgroundColor":"#ffffff"}', '2026-07-03 21:14:40.317981+07', '2026-07-03 21:14:40.317981+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('49cd6f08-3bd8-414b-be0a-48eb9d65841d', '1f2034c5-0aa6-4674-924f-7a7f420ea219', 2, 10, 4, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#ffffff","visibility":"all","content":"<p style=\"text-align:center;\">\"Chè Hà Nội – ngọt vừa đủ để nhớ, thanh vừa đủ để thương\"</p>","author":"Nhân dân Hà Nội","backgroundColor":"#66cddb"}', '2026-07-03 21:14:40.317944+07', '2026-07-03 21:14:40.317944+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('63e1b887-a8ee-4dd1-80e6-b98384dccd14', '1f2034c5-0aa6-4674-924f-7a7f420ea219', 8, 14, 3, true, '{"marginTop":40,"marginBottom":40,"textAlign":"center","textColor":"#333333","visibility":"all","title":"CÁC LOẠI CHÈ NỔI TIẾNG","subtitle":"","items":[{"image":{"url":"https://dauhomemade.vn/apps/uploads/2019/06/Ch%C3%A8-sen-long-nh%C3%A3n-30.000.jpg","scale":"cover","focalPoint":"62% 79%"},"title":"Chè Sen","description":"Hạt sen bùi, nước chè trong và vị ngọt nhẹ, dùng vào mùa hè","tag":""},{"image":{"url":"https://i-giadinh.vnecdn.net/2022/08/22/Buoc-7-7-7927-1661154462.jpg","scale":"cover","focalPoint":"center"},"title":"Chè Đỗ Xanh","description":"Dân dã, ninh mềm, nước thanh mát giúp giải nhiệt","tag":""},{"image":{"url":"https://i-giadinh.vnecdn.net/2022/07/15/Thnhphm11-1657866442-7335-1657866566.jpg","scale":"cover","focalPoint":"51% 49%"},"title":"Chè Đỗ Đen","description":"Dân dã, ninh mềm, nước thanh mát giúp giải nhiệt","tag":""},{"image":{"url":"https://cdn.tgdd.vn/2021/07/CookProduct/1-1200x676-1.jpg","scale":"cover","focalPoint":"69% 53%"},"title":"Chè Khúc Bạch","description":"Biến tấu hiện đại với vị béo nhẹ của kem sữa, trái cây và hạnh nhân.","tag":""}],"backgroundColor":"#ffffff"}', '2026-07-03 21:14:40.317917+07', '2026-07-03 21:14:40.317917+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('6969b533-2472-4d67-a879-bae26aa6e5be', '1f2034c5-0aa6-4674-924f-7a7f420ea219', 2, 2, 1, true, '{"title":"Giới thiệu","content":"<p style=\"text-align:justify;\">Chè Hà Nội là một thế giới đa dạng và phong phú của những món tráng miệng truyền thống. Từ chè thập cẩm, chè sen, chè hạt sen nhãn nhục, đến chè bà ba hay chè đậu xanh – mỗi loại mang một hương vị riêng biệt, tinh tế và khó quên.</p>","image":{"url":"https://ik.imagekit.io/tvlk/blog/2023/11/go-and-share-tiem-che-ha-noi-1.webp","scale":"cover","focalPoint":"32% 75%"},"backgroundColor":"#ffffff","textColor":"#1d758b","textAlign":"right"}', '2026-07-03 21:14:40.317847+07', '2026-07-03 21:14:40.317847+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('6ea595eb-01b2-4408-a9fb-3a5c50dae829', '1f2034c5-0aa6-4674-924f-7a7f420ea219', 5, 7, 7, true, '{"marginTop":0,"marginBottom":0,"textAlign":"left","textColor":"#333333","visibility":"all","title":"","description":"","images":[{"url":{"url":"https://thethaovanhoa.mediacdn.vn/Upload/RxLyK9cSMSneid9zG0DQ/files/2017/06/chekhoaideo.jpg","scale":"cover","focalPoint":"center"},"alt":"Image 1"},{"url":{"url":"https://thethaovanhoa.mediacdn.vn/Upload/RxLyK9cSMSneid9zG0DQ/files/2017/06/chesenthach.jpg","scale":"cover","focalPoint":"center"},"alt":""},{"url":{"url":"https://thethaovanhoa.mediacdn.vn/Upload/RxLyK9cSMSneid9zG0DQ/files/2017/06/checaramen.jpg","scale":"cover","focalPoint":"center"},"alt":""},{"url":{"url":"https://thethaovanhoa.mediacdn.vn/Upload/RxLyK9cSMSneid9zG0DQ/files/2017/06/chetuchon.jpg","scale":"cover","focalPoint":"center"},"alt":""},{"url":{"url":"https://thethaovanhoa.mediacdn.vn/Upload/RxLyK9cSMSneid9zG0DQ/files/2017/06/cheThai.jpg","scale":"cover","focalPoint":"center"},"alt":""},{"url":{"url":"https://thethaovanhoa.mediacdn.vn/Upload/RxLyK9cSMSneid9zG0DQ/files/2017/06/chesau.jpg","scale":"cover","focalPoint":"center"},"alt":""}],"backgroundColor":"#ffffff"}', '2026-07-03 21:14:40.318035+07', '2026-07-03 21:14:40.318035+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('c894703c-d9be-4ddc-aedd-86eb66208539', '1f2034c5-0aa6-4674-924f-7a7f420ea219', 1, 1, 0, true, '{"title":"Chè Hà Nội","subtitle":"Ngọt ngào thanh mát – tinh hoa quà vặt đất kinh kỳ","image":{"url":"https://static.vinwonders.com/production/che-ngon-ha-noi-1.jpg","scale":"cover","focalPoint":"74% 28%"},"textAlign":"left","backgroundColor":"#473d6b","textColor":"#8fe9ff"}', '2026-07-03 21:14:40.317636+07', '2026-07-03 21:14:40.317636+07');
INSERT INTO public."InfographicBlocks" ("Id", "ProductInfographicId", "BlockType", "LayoutType", "SortOrder", "IsVisible", "DataJson", "CreatedAt", "UpdatedAt") VALUES ('d54fbca7-139c-425a-b561-50b0e9751814', '1f2034c5-0aa6-4674-924f-7a7f420ea219', 2, 3, 2, true, '{"title":"Nguồn gốc","content":"<p style=\"text-align:justify;\">Xuất hiện từ hàng trăm năm trước, gắn liền với những gánh hàng rong, quán nước ven hồ và các khu phố cổ. Ban đầu được nấu từ các loại đậu, hạt sen, đỗ xanh... để giải nhiệt và bồi bổ sức khỏe.</p>","image":{"url":"https://www.vntrip.vn/cam-nang/wp-content/uploads/2017/09/che-bobochacha-cua-bac.jpg","scale":"cover","focalPoint":"44% 45%"},"backgroundColor":"#ffffff","textColor":"#6e0b75"}', '2026-07-03 21:14:40.317885+07', '2026-07-03 21:14:40.317885+07');
